import{_ as e,c as t,o as i,a4 as r}from"./chunks/framework.DpC1ZpOZ.js";const g=JSON.parse('{"title":"Key Words","description":"","frontmatter":{},"headers":[],"relativePath":"Concepts/Key_Words.md","filePath":"Concepts/Key_Words.md","lastUpdated":1690829560000}'),o={name:"Concepts/Key_Words.md"},a=r('<h1 id="key-words" tabindex="-1">Key Words <a class="header-anchor" href="#key-words" aria-label="Permalink to &quot;Key Words&quot;">​</a></h1><ol><li><p><strong>Predicate Functions</strong>: are functions that return a single TRUE or FALSE</p></li><li><p><strong>Turing Complete</strong>, <strong>Church-Turing Thesis</strong>: Something is &quot;computable&quot; if and only if it can be computed by a <strong>Turing machine</strong></p><ul><li>Conditional branching, as a result it should have the ability to jump (&quot;go to&quot;)</li><li>Arbitrary amount of memory (infinite RAM)</li></ul></li><li><p><strong>Race Condition</strong>: occurs when two or more threads can access shared data and they try to change it at the same time</p><ul><li><p>Because the thread scheduling algorithm can swap between threads at any time, you don&#39;t know the order in which the threads will attempt to access the shared data</p></li><li><p>Therefore, the result of the change in data is dependent on the thread scheduling algorithm, i.e. both threads are <strong>&quot;racing&quot; to access/change the data</strong></p></li><li><p>Pure functions can help in avoiding race condition issues</p></li></ul></li><li><p>Working set overflow: The &quot;working set&quot; is short hand for &quot;parts of memory that the current algorithm is using&quot; and is determined by which parts of memory the CPU just happens to access</p></li><li><p>P95 Latency (P% Latency): The P95 Threshold indicates that 5% of transaction durations are greater than the threshold. For example, if the P95 threshold is 50 milliseconds, then 5% of transactions exceeded that threshold, taking longer than 50 milliseconds</p></li><li><p>Software Rot</p></li><li><p>Use-After-Free (UAF) is a vulnerability related to incorrect use of dynamic memory during program operation</p></li><li><p>Write-what-where Condition: Any condition where the attacker has the ability to write an arbitrary value to an arbitrary location, often as the result of a buffer overflow.</p></li><li><p>Global Offset Table (GOT): is a section of a computer program&#39;s (executables and shared libraries) memory used to enable computer program code compiled as an ELF file to run correctly, independent of the memory address where the program&#39;s code or data is loaded at runtime.</p></li><li><p>Convex hull</p></li></ol><p>RAII (Resource acquisition is initialization)</p><p>Semantic Versioning:</p><ul><li>Major.Minor.Patch release</li><li>Caret (^): All minor and patches OK (^1.x.x)</li><li>Tilde (~): All patches only (~1.5.x)</li></ul><h2 id="floating-point-numbers" tabindex="-1">Floating Point Numbers <a class="header-anchor" href="#floating-point-numbers" aria-label="Permalink to &quot;Floating Point Numbers&quot;">​</a></h2><p><em>IEEE 754</em>: Floating point number specification</p><ul><li>It is a compression algorithm</li></ul><table tabindex="0"><thead><tr><th>Bits</th><th>Precision</th></tr></thead><tbody><tr><td><em>16 bit</em></td><td>Half Precision</td></tr><tr><td><em>32 bit</em></td><td>Single Precision</td></tr><tr><td><em>64 bit</em></td><td>Double Precision</td></tr><tr><td><em>128 bit</em></td><td>Quadruple Precision</td></tr><tr><td><em>256 bit</em></td><td>Octuple Precision</td></tr></tbody></table><p>Floating point numbers in 16 Bit System:</p><p>The floating point number&#39;s binary representation is split into 3-parts:</p><ol><li><p><em>Sign (1 Bit)</em>:</p><ul><li>Number is Positive or Negative</li></ul></li><li><p><em>Exponent (5 Bits)</em>:</p><ul><li>Represents a range</li></ul><table tabindex="0"><thead><tr><th style="text-align:center;">Exponent (<code>n</code>)</th><th style="text-align:center;">Power Range (<code>2^n</code>)</th><th style="text-align:center;">Numerical Range</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td style="text-align:center;">[0, 1]</td><td style="text-align:center;">[1, 2]</td></tr><tr><td style="text-align:center;">1</td><td style="text-align:center;">[1, 2]</td><td style="text-align:center;">[2, 4]</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:center;">[2, 3]</td><td style="text-align:center;">[4, 8]</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:center;">[3, 4]</td><td style="text-align:center;">[8, 16]</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:center;">[4, 5]</td><td style="text-align:center;">[16, 32]</td></tr></tbody></table></li><li><p><em>Mantissa (10 Bits)</em>:</p><ul><li><code>(Number - lower bound) / (upper bound - lower bound)</code></li></ul></li></ol><p>Formal that represents a floating point number: <strong><code>N = (-1)^sign * 1.mantissa * 2^(exponent - 15)</code></strong></p><p>According to IEEE 754 spec:</p><ul><li><p><code>-0</code> if <em><code>sign=1</code></em>, <em><code>exponent=00000</code></em>, and <em><code>mantissa=0000000000</code></em></p></li><li><p><code>INFINITY</code> if <em><code>exponent=11111</code></em> and <em><code>mantissa=0000000000</code></em></p><ul><li><code>-INFINITY</code> if <em><code>sign=1</code></em></li></ul></li><li><p><code>NaN</code> if <em><code>exponent=11111</code></em> and <em><code>mantissa=someValue</code></em></p><ul><li>There are man <code>NaN</code></li></ul></li><li><p><code>2^0</code>: de-normalized number</p></li></ul><p>References:</p><ul><li><p><a href="https://en.wikipedia.org/wiki/Floating-point_arithmetic" target="_blank" rel="noreferrer">Floating Point Arithmetic</a></p></li><li><p><a href="https://en.wikipedia.org/wiki/Half-precision_floating-point_format" target="_blank" rel="noreferrer">16 Bit Floats</a></p></li><li><p><a href="https://ieeexplore.ieee.org/document/30711" target="_blank" rel="noreferrer">IEEE 754 Spec</a></p></li><li><p><a href="https://fabiensanglard.net/floating_point_visually_explained/" target="_blank" rel="noreferrer">Fabien Sanglard&#39;s awesome blog on the subject</a></p></li><li><p><a href="https://en.wikipedia.org/wiki/Denormal_number" target="_blank" rel="noreferrer">Denormalised Numbers</a></p></li><li><p><a href="https://github.com/LowLevelJavaScript/Floating-Point-Implemented-In-JS" target="_blank" rel="noreferrer">Low Level JavaScript: Github Repo</a></p></li></ul>',17),n=[a];function l(s,d,c,p,h,m){return i(),t("div",null,n)}const b=e(o,[["render",l]]);export{g as __pageData,b as default};
